/*
 * Minimum Cost Spanning Tree - Kruskal's Algorithm
 * Implementation in C with Union-Find
 * 
 * Time Complexity: O(E log E) or O(E log V)
 * Space Complexity: O(V + E)
 */

#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX_VERTICES 100
#define MAX_EDGES 100

/* Edge structure representing an edge in the graph */
typedef struct {
 int u; // Source vertex
 int v; // Destination vertex
 int weight; // Edge weight
} Edge;

/* Union-Find data structure */
typedef struct {
 int parent[MAX_VERTICES];
 int rank[MAX_VERTICES];
} UnionFind;

/* Initialize Union-Find with each vertex in its own set */
void makeSet(UnionFind *uf, int n) {
 for (int i = 0; i < n; i++) {
 uf->parent[i] = i;
 uf->rank[i] = 0;
 }
}

/* Find with path compression */
int find(UnionFind *uf, int x) {
 if (uf->parent[x] != x) {
 uf->parent[x] = find(uf, uf->parent[x]); // Path compression
 }
 return uf->parent[x];
}

/* Union by rank */
void unionSets(UnionFind *uf, int x, int y) {
 int rootX = find(uf, x);
 int rootY = find(uf, y);

 if (rootX == rootY) {
 return; // Already in the same set
 }

 // Union by rank: attach smaller tree under larger tree
 if (uf->rank[rootX] < uf->rank[rootY]) {
 uf->parent[rootX] = rootY;
 } else if (uf->rank[rootX] > uf->rank[rootY]) {
 uf->parent[rootY] = rootX;
 } else {
 uf->parent[rootY] = rootX;
 uf->rank[rootX]++;
 }
}

/* Comparison function for sorting edges by weight (qsort) */
int compareEdges(const void *a, const void *b) {
 Edge *edgeA = (Edge *)a;
 Edge *edgeB = (Edge *)b;
 return edgeA->weight - edgeB->weight;
}

/* Kruskal's Algorithm */
void kruskalMST(Edge edges[], int numEdges, int numVertices) {
 // Step 1: Sort all edges by weight in non-decreasing order
 qsort(edges, numEdges, sizeof(Edge), compareEdges);

 printf("\nEdges sorted by weight:\n");
 for (int i = 0; i < numEdges; i++) {
 printf(" Edge (%d, %d): weight = %d\n", 
 edges[i].u, edges[i].v, edges[i].weight);
 }

 // Step 2: Initialize Union-Find
 UnionFind uf;
 makeSet(&uf, numVertices);

 // Step 3: Build MST by selecting edges
 printf("\n--- Building MST ---\n");

 int mstWeight = 0;
 int edgeCount = 0;

 printf("MST Edges (Kruskal's Algorithm):\n");

 for (int i = 0; i < numEdges && edgeCount < numVertices - 1; i++) {
 int u = edges[i].u;
 int v = edges[i].v;
 int w = edges[i].weight;

 // Check if u and v are in different components
 if (find(&uf, u) != find(&uf, v)) {
 // Add edge to MST
 printf(" Added: (%d, %d) weight = %d\n", u, v, w);
 unionSets(&uf, u, v);
 mstWeight += w;
 edgeCount++;
 } else {
 printf(" Skipped: (%d, %d) weight = %d (forms cycle)\n", u, v, w);
 }
 }

 // Print result
 printf("\n=================================\n");
 printf("Total MST Weight: %d\n", mstWeight);
 printf("Number of edges in MST: %d\n", edgeCount);
 printf("=================================\n");
}

/* Print the graph */
void printGraph(Edge edges[], int numEdges) {
 printf("Original Graph (Vertex labels adjusted for 0-indexed):\n");
 printf("Vertices: 0, 1, 2, 3\n");
 printf("Edges:\n");
 for (int i = 0; i < numEdges; i++) {
 printf(" (%d, %d) weight = %d\n", 
 edges[i].u, edges[i].v, edges[i].weight);
 }
}

int main() {
 /*
 * Example Graph from the topic:
 * 
 * 0 ---4--- 1
 * | / |
 * 8 2 6
 * | / |
 * 2 ---3--- 3
 * 
 * Edges: (0,1,4), (0,2,8), (1,2,2), (1,3,6), (2,3,3)
 * MST: {(1,2,2), (2,3,3), (0,1,4)} = 9
 */

 int numVertices = 4;
 int numEdges = 5;

 Edge edges[] = {
 {0, 1, 4},
 {0, 2, 8},
 {1, 2, 2},
 {1, 3, 6},
 {2, 3, 3}
 };

 printf("========================================\n");
 printf("MINIMUM COST SPANNING TREE\n");
 printf("Kruskal's Algorithm Implementation\n");
 printf("========================================\n");

 printGraph(edges, numEdges);

 // Run Kruskal's Algorithm
 kruskalMST(edges, numEdges, numVertices);

 return 0;
}

import java.util.*;

/**
 * Minimum Cost Spanning Tree - Prim's Algorithm
 * Implementation in Java with Priority Queue (Min-Heap)
 * 
 * Time Complexity: O(E log V) using binary heap
 * Space Complexity: O(V + E)
 */
public class PrimMST {

 // Inner class to represent an edge
 static class Edge {
 int to; // Destination vertex
 int weight; // Edge weight

 Edge(int to, int weight) {
 this.to = to;
 this.weight = weight;
 }
 }

 // Inner class for priority queue entries
 static class PQEntry {
 int vertex;
 int key; // Minimum weight to connect to MST
 int parent; // Parent vertex in MST

 PQEntry(int vertex, int key, int parent) {
 this.vertex = vertex;
 this.key = key;
 this.parent = parent;
 }
 }

 private int numVertices;
 private List<Edge>[] adjacencyList;

 @SuppressWarnings("unchecked")
 public PrimMST(int numVertices) {
 this.numVertices = numVertices;
 this.adjacencyList = new ArrayList[numVertices];

 // Initialize adjacency list
 for (int i = 0; i < numVertices; i++) {
 adjacencyList[i] = new ArrayList<>();
 }
 }

 /**
 * Add an undirected edge to the graph
 */
 public void addEdge(int u, int v, int weight) {
 adjacencyList[u].add(new Edge(v, weight));
 adjacencyList[v].add(new Edge(u, weight));
 }

 /**
 * Find MST using Prim's algorithm with Priority Queue
 */
 public List<int[]> findMST(int startVertex) {
 // Arrays to store MST information
 int[] key = new int[numVertices]; // Min weight to connect to MST
 int[] parent = new int[numVertices]; // Parent in MST
 boolean[] inMST = new boolean[numVertices]; // Vertex in MST?

 // Initialize
 Arrays.fill(key, Integer.MAX_VALUE);
 Arrays.fill(parent, -1);
 key[startVertex] = 0;

 // Priority queue: min-heap based on key value
 // Using custom comparator for min-heap behavior
 PriorityQueue<PQEntry> pq = new PriorityQueue<>(
 numVertices, 
 (a, b) -> Integer.compare(a.key, b.key)
 );

 // Add starting vertex
 pq.offer(new PQEntry(startVertex, 0, -1));

 System.out.println("--- Prim's Algorithm Steps ---\n");

 while (!pq.isEmpty()) {
 // Extract minimum key vertex
 PQEntry current = pq.poll();
 int u = current.vertex;

 // Skip if already in MST
 if (inMST[u]) {
 continue;
 }

 // Add to MST
 inMST[u] = true;

 if (parent[u] != -1) {
 System.out.printf(" Vertex %d added to MST via edge (%d, %d) weight = %d%n",
 u, parent[u], u, key[u]);
 }

 // Update keys of adjacent vertices
 for (Edge edge : adjacencyList[u]) {
 int v = edge.to;
 int weight = edge.weight;

 // If v is not in MST and weight is smaller than current key
 if (!inMST[v] && weight < key[v]) {
 key[v] = weight;
 parent[v] = u;
 pq.offer(new PQEntry(v, key[v], u));
 }
 }
 }

 // Build MST edge list
 List<int[]> mstEdges = new ArrayList<>();
 int totalWeight = 0;

 for (int v = 0; v < numVertices; v++) {
 if (parent[v] != -1) {
 mstEdges.add(new int[]{parent[v], v, key[v]});
 totalWeight += key[v];
 }
 }

 return mstEdges;
 }

 /**
 * Print the MST results
 */
 public void printMST(List<int[]> mstEdges, int totalWeight) {
 System.out.println("\n========================================");
 System.out.println("MINIMUM SPANNING TREE (Prim's Algorithm)");
 System.out.println("========================================");
 System.out.println("\nMST Edges:");

 for (int[] edge : mstEdges) {
 System.out.printf(" (%d, %d) weight = %d%n", 
 edge[0], edge[1], edge[2]);
 }

 System.out.printf("\nTotal MST Weight: %d%n", totalWeight);
 System.out.println("Number of edges: " + mstEdges.size());
 System.out.println("========================================");
 }

 /**
 * Print the original graph
 */
 public void printGraph() {
 System.out.println("Original Graph:");
 System.out.println("Vertices: 0, 1, 2, 3");
 System.out.println("Edges:");

 Set<String> printed = new HashSet<>();
 for (int u = 0; u < numVertices; u++) {
 for (Edge edge : adjacencyList[u]) {
 // Avoid printing edges twice (undirected)
 String key = Math.min(u, edge.to) + "-" + Math.max(u, edge.to);
 if (!printed.contains(key)) {
 System.out.printf(" (%d, %d) weight = %d%n", u, edge.to, edge.weight);
 printed.add(key);
 }
 }
 }
 }

 public static void main(String[] args) {
 /*
 * Example Graph from the topic:
 * 
 * 0 ---4--- 1
 * | / |
 * 8 2 6
 * | / |
 * 2 ---3--- 3
 * 
 * Edges: (0,1,4), (0,2,8), (1,2,2), (1,3,6), (2,3,3)
 * MST: {(1,2,2), (2,3,3), (0,1,4)} = 9
 */

 int numVertices = 4;
 PrimMST graph = new PrimMST(numVertices);

 // Add edges to the graph
 graph.addEdge(0, 1, 4); // Edge 0-1 with weight 4
 graph.addEdge(0, 2, 8); // Edge 0-2 with weight 8
 graph.addEdge(1, 2, 2); // Edge 1-2 with weight 2
 graph.addEdge(1, 3, 6); // Edge 1-3 with weight 6
 graph.addEdge(2, 3, 3); // Edge 2-3 with weight 3

 System.out.println("========================================");
 System.out.println("MINIMUM COST SPANNING TREE DEMO");
 System.out.println("========================================");

 graph.printGraph();

 // Find MST starting from vertex 0
 List<int[]> mstEdges = graph.findMST(0);

 // Calculate total weight
 int totalWeight = 0;
 for (int[] edge : mstEdges) {
 totalWeight += edge[2];
 }

 graph.printMST(mstEdges, totalWeight);
 }
}
